    """Capture JWT tokens from HTTP responses and store them for later use."""
    pattern = r"eyJ[A-Za-z0-9_-]+\.eyJ[A-Za-z0-9_-]+\.[A-Za-z0-9_-]*"
    tokens = re.findall(pattern, response_text)
    if not tokens:
        return

    for token in tokens[:1]:
        try:
            parts = token.split(".")
            padded = parts[1] + "=" * (4 - len(parts[1]) % 4)
            payload = json.loads(base64.urlsafe_b64decode(padded).decode())
            email = payload.get("email", "")
            role  = "admin" if "admin" in email.lower() else "user"
            http_tool.set_auth_token(role, token)
            state_store.set_auth_token(role, token)
            logger.info(f"[orchestrator] Captured {role} JWT (email: {email})")
        except Exception:
            pass

